1тЖТimport React, { useState, useEffect } from 'react';
2тЖТimport { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
3тЖТimport Login from './components/Login';
4тЖТimport Dashboard from './components/Dashboard';
5тЖТimport AdminPanel from './components/AdminPanel';
6тЖТimport MasterPanel from './components/MasterPanel';
7тЖТimport NazoratchiPanel from './components/NazoratchiPanel';
8тЖТimport UsersPanel from './components/UsersPanel';
9тЖТimport ReportsPanel from './components/ReportsPanel';
10тЖТimport MechanicPanel from './components/MechanicPanel';
11тЖТimport Sidebar from './components/Sidebar';
12тЖТ
13тЖТfunction App() {
14тЖТ  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);
15тЖТ  const [activeTab, setActiveTab] = useState('run');
16тЖТ
17тЖТ  const handleLogin = (userData) => {
18тЖТ    localStorage.setItem('user', JSON.stringify(userData));
19тЖТ    setUser(userData);
20тЖТ  };
21тЖТ
22тЖТ  const handleLogout = () => {
23тЖТ    localStorage.removeItem('user');
24тЖТ    localStorage.removeItem('token');
25тЖТ    setUser(null);
26тЖТ    setActiveTab('run');
27тЖТ  };
28тЖТ
29тЖТ  const renderContent = () => {
30тЖТ    switch (activeTab) {
31тЖТ      case 'run':
32тЖТ        return <Dashboard user={user} />;
33тЖТ      case 'report':
34тЖТ        return <ReportsPanel user={user} />;
35тЖТ      case 'mechanic':
36тЖТ        return <MechanicPanel user={user} />;
37тЖТ      case 'admin':
38тЖТ        return <AdminPanel user={user} />;
39тЖТ      case 'master':
40тЖТ        return <MasterPanel user={user} />;
41тЖТ      case 'nazoratchi':
42тЖТ        return <NazoratchiPanel user={user} />;
43тЖТ      case 'users':
44тЖТ        return <UsersPanel user={user} />;
45тЖТ      default:
46тЖТ        return <Dashboard user={user} />;
47тЖТ    }
48тЖТ  };
49тЖТ
50тЖТ  return (
51тЖТ    <Router>
52тЖТ      <Routes>
53тЖТ        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
54тЖТ        <Route path="/*" element={
55тЖТ          user ? (
56тЖТ            <div className="app-container">
57тЖТ              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
58тЖТ              <div className="main-content">
59тЖТ                {renderContent()}
60тЖТ              </div>
61тЖТ            </div>
62тЖТ          ) : (
63тЖТ            <Navigate to="/login" />
64тЖТ          )
65тЖТ        } />
66тЖТ      </Routes>
67тЖТ    </Router>
68тЖТ  );
69тЖТ}
70тЖТ
71тЖТexport default App;
EOF

