    flex-direction: row;
    flex-wrap: wrap;
    gap: 0;
    align-items: center;
    flex-shrink: 0;
  }
  .sidebar > div:first-child {
    width: 100%;
    margin-bottom: 0.25rem;
  }
  .sidebar > div:first-child h1 {
    font-size: 0.9rem !important;
    margin: 0 !important;
  }
  .sidebar nav {
    flex-direction: row !important;
    flex-wrap: wrap;
    gap: 3px !important;
    width: 100%;
  }
  .sidebar nav button {
    padding: 5px 8px !important;
    font-size: 0.6rem !important;
    flex: 1;
    min-width: calc(33% - 3px);
    justify-content: center;
    border-radius: 6px !important;
  }
  .sidebar > div:last-child {
    width: 100%;
    padding: 0.25rem !important;
    margin-top: 0.25rem !important;
    display: flex;
    align-items: center;
    justify-content: space-between;
  }
  .sidebar > div:last-child > div {
    margin-bottom: 0 !important;
    font-size: 0.7rem !important;
  }
  .sidebar > div:last-child button {
    width: auto !important;
    padding: 4px 10px !important;
    font-size: 0.7rem !important;
  }
}

/* тХРтХРтХР STAT WIDGETS тХРтХРтХР */
.stat-widget {
  background: var(--card);
  border-radius: 1rem;
  padding: 1.25rem;
  margin-bottom: 1rem;
  border: 1px solid var(--panel-border);
}

.stat-value {
  font-size: 2rem;
  font-weight: 800;
  line-height: 1;
}

.stat-label {
  color: var(--text-muted);
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 1px;
}

@media (max-width: 768px) {
  .stat-widget {
    padding: 0.5rem;
    margin-bottom: 0;
    border-radius: 0.75rem;
  }
  .stat-value {
    font-size: 1.2rem;
  }
  .stat-label {
    font-size: 0.6rem;
    letter-spacing: 0;
  }
}

/* тХРтХРтХР MAIN CONTENT тХРтХРтХР */
.main-content {
  flex: 1;
  padding: 1rem;
  background: #0b0f1a;
  overflow: auto;
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
}

@media (max-width: 768px) {
  .main-content {
    padding: 0.25rem;
    flex: 1;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    min-height: 0;
  }
}

/* тХРтХРтХР FACTORY MAP тХРтХРтХР */
.factory-map-container {
  flex: 1;
  overflow: auto;
  border-radius: 16px;
  padding: 8px;
  position: relative;
}

@media (max-width: 768px) {
  .factory-map-container {
    border-radius: 8px;
    padding: 0;
    overflow: auto;
    -webkit-overflow-scrolling: touch;
    flex: 1;
    min-height: 0;
  }
}

.factory-bg {
  position: relative;
  width: 1200px;
  height: 800px;
  background: #111827;
  border-radius: 8px;
  border: 3px solid #334155;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  background-image: 
    linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px);
  background-size: 25px 25px;
}

@media (max-width: 768px) {
  .factory-bg {
    width: 1200px;
    height: 800px;
    transform: scale(0.55);
    transform-origin: top left;
    border-radius: 6px;
    border-width: 2px;
  }
}

@media (max-width: 480px) {
  .factory-bg {
    transform: scale(0.4);
    transform-origin: top left;
  }
}

.zone-label {
  position: absolute;
  color: var(--text-muted);
  font-weight: 700;
  font-size: 0.9rem;
  pointer-events: none;
  text-transform: uppercase;
  letter-spacing: 3px;
  opacity: 0.5;
}

/* тХРтХРтХР MACHINE NODES тХРтХРтХР */
.machine-node {
  position: absolute;
  width: 48px;
  height: 48px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(4px);
  touch-action: manipulation;
}

.machine-node:hover {
  transform: scale(1.2) translateY(-5px);
  z-index: 10;
  box-shadow: 0 0 20px rgba(0, 210, 255, 0.5);
}

.machine-node.is-focused {
  border-color: var(--primary);
  box-shadow: 0 0 30px rgba(0, 210, 255, 0.6);
  z-index: 5;
}

.smart-pulse {
  position: absolute;
  width: 100%;
  height: 100%;
  border: 2px solid var(--primary);
  border-radius: 50%;
  animation: smart-ripple 1.5s infinite;
  pointer-events: none;
}

@keyframes smart-ripple {
  0% { transform: scale(0.5); opacity: 1; }
  100% { transform: scale(2.5); opacity: 0; }
}

.machine-node.running {
  background: rgba(57, 255, 20, 0.1);
  color: var(--neon-green);
  border-color: var(--neon-green);
  box-shadow: 0 0 10px rgba(57, 255, 20, 0.2);
  animation: neon-pulse-green 2s infinite;
}

.machine-node.stopped {
  background: rgba(255, 49, 49, 0.1);
  color: var(--neon-red);
  border-color: var(--neon-red);
}

.machine-node.warning {
  background: rgba(255, 234, 0, 0.1);
  color: var(--neon-yellow);
  border-color: var(--neon-yellow);
  animation: neon-pulse-yellow 2s infinite;
}

.machine-node.searching {
  background: rgba(168, 85, 247, 0.2);
  color: #c084fc;
  border-color: #a855f7;
  box-shadow: 0 0 15px rgba(168, 85, 247, 0.4);
  animation: neon-pulse-violet 2s infinite;
}

.searching .icon {
  animation: searching-rotate 2s linear infinite;
}

@keyframes searching-rotate {
  0% { transform: scale(1); opacity: 0.7; }
  50% { transform: scale(1.1); opacity: 1; }
  100% { transform: scale(1); opacity: 0.7; }
}

@keyframes neon-pulse-green {
  0% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
  50% { box-shadow: 0 0 25px rgba(57, 255, 20, 0.7), 0 0 40px rgba(57, 255, 20, 0.3); }
  100% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
}

@keyframes neon-pulse-violet {
  0% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
  50% { box-shadow: 0 0 25px rgba(168, 85, 247, 0.7), 0 0 40px rgba(168, 85, 247, 0.3); }
  100% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
}

/* тХРтХРтХР TAB SWITCHER тХРтХРтХР */
.tab-switcher {
  display: flex;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  padding: 3px;
  gap: 3px;
}

.tab-switcher button {
  background: transparent;
  border: none;
  color: var(--text-muted);
  font-size: 0.65rem;
  font-weight: 800;
  padding: 5px 12px;
  border-radius: 6px;
  cursor: pointer;
  transition: 0.2s;
}

.tab-switcher button.active {
  background: var(--primary);
  color: white;
  box-shadow: 0 0 10px var(--primary);
}

/* тХРтХРтХР DIAG PANEL тХРтХРтХР */
.diag-panel {
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
  margin-bottom: 2rem;
}

.diag-item {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.diag-label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-muted);
  display: flex;
  justify-content: space-between;
}

.diag-label span {
  color: var(--text);
  font-family: monospace;
}

.diag-bar-bg {
  height: 8px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 4px;
  overflow: hidden;
}

.diag-bar {
  height: 100%;
  border-radius: 4px;
  transition: width 0.5s ease-in-out;
}

.diag-bar.ram {
  background: linear-gradient(90deg, #38bdf8, #0ea5e9);
  box-shadow: 0 0 10px rgba(56, 189, 248, 0.3);
}

.diag-bar.rom {
  background: linear-gradient(90deg, #a855f7, #8b5cf6);
  box-shadow: 0 0 10px rgba(168, 85, 247, 0.3);
}

/* тХРтХРтХР MODAL тХРтХРтХР */
.modal-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  padding: 1rem;
}

.modal-content {
  background: var(--bg-panel);
  border: 1px solid var(--panel-border);
  border-radius: 24px;
  padding: 2rem;
  width: 92%;
  max-width: 450px;
  max-height: 85vh;
  overflow-y: auto;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
}

@media (max-width: 768px) {
  .modal-overlay {
    padding: 0;
    align-items: flex-end;
  }
  .modal-content {
    width: 100%;
    max-width: 100%;
    border-radius: 24px 24px 0 0;
    padding: 1.25rem;
    max-height: 80vh;
    max-height: 80dvh;
  }
}

/* тХРтХРтХР FORM ELEMENTS тХРтХРтХР */
.input-field {
  width: 100%;
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  color: var(--text-main);
  font-size: 1rem;
  margin-bottom: 1rem;
  outline: none;
  transition: 0.2s;
}

.input-field:focus {
