  padding: 14px;
  background: var(--primary);
  color: #0a0f1a;
  border: none;
  border-radius: 12px;
  font-size: 1rem;
  font-weight: 800;
  cursor: pointer;
  transition: 0.2s;
  touch-action: manipulation;
}

.btn-submit:hover {
  filter: brightness(1.1);
  transform: translateY(-1px);
}

.btn-submit:active {
